function solve(nums: number[]): boolean {
    const n = nums.length;
    for (let p = 1; p < n - 1; p++) {
        for (let q = p + 1; q < n - 1; q++) {
            // Check first part: 0...p is strictly increasing
            let first = true;
            for (let i = 0; i < p; i++) {
                if (nums[i] >= nums[i + 1]) {
                    first = false;
                    break;
                }
            }
            if (!first) continue;

            // Check second part: p...q is strictly decreasing
            let second = true;
            for (let i = p; i < q; i++) {
                if (nums[i] <= nums[i + 1]) {
                    second = false;
                    break;
                }
            }
            if (!second) continue;

            // Check third part: q...n-1 is strictly increasing
            let third = true;
            for (let i = q; i < n - 1; i++) {
                if (nums[i] >= nums[i + 1]) {
                    third = false;
                    break;
                }
            }
            if (third) {
                return true;
            }
        }
    }
    return false;
}

